1	/* eslint-disable bim-ai/no-hex-in-chrome -- pre-v3 hex literals; remove when this file is migrated in B4 Phase 2 */
2	import type { Element } from '@bim-ai/core';
3	
4	import {
5	  useEffect,
6	  useMemo,
7	  useRef,
8	  useState,
9	  type PointerEvent as ReactPointerEvent,
10	} from 'react';
11	
12	import type { SheetViewportMmDraft } from './sheetViewportAuthoring';
13	import {
14	  readViewportMmBox,
15	  readViewportPresentationMeta,
16	  SheetViewportEditor,
17	  normalizeViewportRaw,
18	  clampViewportMmPosition,
19	  clampViewportMmBox,
20	} from './sheetViewportAuthoring';
21	import {
22	  SheetTitleblockEditor,
23	  normalizeTitleblockDraftFromSheet,
24	} from './sheetTitleblockAuthoring';
25	import { SheetDocumentationManifest } from './SheetDocumentationManifest';
26	import { parseSheetViewRef, resolveViewportTitleFromRef } from './sheetViewRef';
27	import {
28	  buildPlaceholderDetailTitle,
29	  detailCalloutUnresolvedReason,
30	} from './sheetDetailCalloutReadout';
31	import { SectionViewportSvg } from './sectionViewportSvg';
32	import {
33	  formatSheetRevIssTitleblockDisplaySegmentV1,
34	  normalizeTitleblockRevisionIssueV1,
35	} from './sheetRevisionIssueManifestV1';
36	
37	type SheetEl = Extract<Element, { kind: 'sheet' }>;
38	
39	function clientToSvgMm(
40	  svg: SVGSVGElement,
41	  clientX: number,
42	  clientY: number,
43	): { x: number; y: number } {
44	  const pt = svg.createSVGPoint();
45	  pt.x = clientX;
46	  pt.y = clientY;
47	  const ctm = svg.getScreenCTM();
48	  if (!ctm) {
49	    return { x: 0, y: 0 };
50	  }
51	  const sp = pt.matrixTransform(ctm.inverse());
52	  return { x: sp.x, y: sp.y };
53	}
54	
55	function SheetCanvasWithSheet(props: {
56	  sheet: SheetEl;
57	  evidenceFullBleed?: boolean;
58	  modelId?: string;
59	  elementsById: Record<string, Element>;
60	  onUpsertSemantic?: (cmd: Record<string, unknown>) => void;
61	}) {
62	  const { sheet: sh, evidenceFullBleed, modelId, elementsById } = props;
63	
64	  const bleed = evidenceFullBleed ?? false;
65	  const wMm =
66	    typeof sh.paperWidthMm === 'number' && Number.isFinite(sh.paperWidthMm)
67	      ? sh.paperWidthMm
68	      : 42_000;
69	  const hMm =
70	    typeof sh.paperHeightMm === 'number' && Number.isFinite(sh.paperHeightMm)
71	      ? sh.paperHeightMm
72	      : 29_700;
73	
74	  const vps = (sh.viewportsMm ?? []) as Array<Record<string, unknown>>;
75	  const nextDraftBase = (): SheetViewportMmDraft[] =>
76	    vps.map((vp, i) => normalizeViewportRaw(vp, i));
77	  const [vpDrafts, setVpDrafts] = useState<SheetViewportMmDraft[]>(() => nextDraftBase());
78	
79	  const [tbDraft, setTbDraft] = useState(() => normalizeTitleblockDraftFromSheet(sh));
80	
81	  const svgRef = useRef<SVGSVGElement | null>(null);
82	  const dragRef = useRef<{ index: number; grabDX: number; grabDY: number } | null>(null);
83	  const resizeRef = useRef<{ index: number } | null>(null);
84	
85	  const authoring = Boolean(props.onUpsertSemantic);
86	
87	  const tp = sh.titleblockParameters ?? {};
88	  const sheetNo = tp.sheetNumber ?? tp.sheetNo ?? '';
89	  const revision = tp.revision ?? '';
90	  const project = tp.projectName ?? tp.project ?? '';
91	  const drawn = tp.drawnBy ?? '';
92	  const chk = tp.checkedBy ?? '';
93	  const issued = tp.issueDate ?? tp.date ?? '';
94	
95	  const hdrParts: string[] = [];
96	  if (String(sheetNo).trim()) hdrParts.push(String(sheetNo).trim());
97	  if (String(revision).trim()) hdrParts.push(`Rev ${String(revision).trim()}`);
98	  const hdr = hdrParts.join(' · ');
99	
100	  const footerLines: string[] = [];
101	  if (hdr) footerLines.push(hdr);
102	  if (String(project).trim()) footerLines.push(String(project).trim());
103	  if (String(drawn).trim() || String(chk).trim()) {
104	    footerLines.push(
105	      `Drn ${String(drawn).trim()} · Chk ${String(chk).trim()}`.replace(/\s*·\s*$/, '').trim(),
106	    );
107	  }
108	  if (String(issued).trim()) footerLines.push(String(issued).trim());
109	
110	  const revIssSeg = formatSheetRevIssTitleblockDisplaySegmentV1(
111	    normalizeTitleblockRevisionIssueV1(tp as Record<string, string>),
112	  );
113	
114	  const footerY0 = Math.max(2800, hMm - 5200);
115	  const xRight = wMm - 2600;
116	
117	  const scrollCls = bleed ? '' : ' max-h-[360px]';
118	
119	  const [planLegendHints, setPlanLegendHints] = useState<
120	    Record<string, { rowCount: number; digestPrefix: string }>
121	  >({});
122	
123	  useEffect(() => {
124	    if (!modelId) {
125	      setPlanLegendHints({});
126	      return;
127	    }
128	    const ac = new AbortController();
129	    void (async () => {
130	      try {
131	        const res = await fetch(`/api/models/${encodeURIComponent(modelId)}/evidence-package`, {
132	          signal: ac.signal,
133	        });
134	        if (!res.ok) {
135	          setPlanLegendHints({});
136	          return;
137	        }
138	        const payload = JSON.parse(await res.text()) as Record<string, unknown>;
139	        const rows = payload.deterministicSheetEvidence;
140	        if (!Array.isArray(rows)) {
141	          setPlanLegendHints({});
142	          return;
143	        }
144	        const drow = (rows as Record<string, unknown>[]).find(
145	          (r) => String(r.sheetId ?? '') === sh.id,
146	        );
147	        if (!drow) {
148	          setPlanLegendHints({});
149	          return;
150	        }
151	        const hints = drow.planRoomProgrammeLegendHints_v0;
152	        if (!Array.isArray(hints)) {
153	          setPlanLegendHints({});
154	          return;
155	        }
156	        const next: Record<string, { rowCount: number; digestPrefix: string }> = {};
157	        for (const h of hints) {
158	          if (!h || typeof h !== 'object') continue;
159	          const vid = String((h as { viewportId?: unknown }).viewportId ?? '').trim();
160	          if (!vid) continue;
161	          const rc = (h as { rowCount?: unknown }).rowCount;
162	          const n = typeof rc === 'number' ? rc : Number(rc);
163	          const dig = String((h as { legendDigestSha256?: unknown }).legendDigestSha256 ?? '');
164	          next[vid] = {
165	            rowCount: Number.isFinite(n) ? n : 0,
166	            digestPrefix: dig.slice(0, 8),
167	          };
168	        }
169	        setPlanLegendHints(next);
170	      } catch (e) {
171	        if (e instanceof DOMException && e.name === 'AbortError') return;
172	        setPlanLegendHints({});
173	      }
174	    })();
175	    return () => ac.abort();
176	  }, [modelId, sh.id]);
177	
178	  const paintRows: Array<{
179	    key: string;
180	    xMm: number;
181	    yMm: number;
182	    widthMm: number;
183	    heightMm: number;
184	    viewRef: string;
185	    label: string;
186	    detailNumber: string;
187	    scale: string;
188	    viewportLocked: boolean;
189	    viewportRole: 'standard' | 'detail_callout';
190	    index: number;
191	  }> = authoring
192	    ? vpDrafts.map((d, index) => ({
193	        key: d.viewportId,
194	        xMm: d.xMm,
195	        yMm: d.yMm,
196	        widthMm: d.widthMm,
197	        heightMm: d.heightMm,
198	        viewRef: d.viewRef,
199	        label: d.label,
200	        detailNumber: d.detailNumber,
201	        scale: d.scale,
202	        viewportLocked: d.viewportLocked,
203	        viewportRole: d.viewportRole,
204	        index,
205	      }))
206	    : vps.map((vpRaw, index) => {
207	        const vp = vpRaw as Record<string, unknown>;
208	        const n = normalizeViewportRaw(vp, index);
209	        const box = readViewportMmBox(vp);
210	        const viewRefRaw = vp.viewRef ?? vp.view_ref;
211	        const label = typeof vp.label === 'string' ? vp.label : 'Viewport';
212	        const meta = readViewportPresentationMeta(vp);
213	        return {
214	          key:
215	            n.viewportId ||
216	            String(vp.viewportId ?? vp.viewport_id ?? `${box.xMm}_${box.yMm}_${index}`),
217	          xMm: box.xMm,
218	          yMm: box.yMm,
219	          widthMm: box.widthMm,
220	          heightMm: box.heightMm,
221	          viewRef: typeof viewRefRaw === 'string' ? viewRefRaw : '',
222	          label,
223	          detailNumber: meta.detailNumber,
224	          scale: meta.scale,
225	          viewportLocked: meta.viewportLocked,
226	          viewportRole: n.viewportRole,
227	          index,
228	        };
229	      });
230	
231	  const beginDrag = (e: ReactPointerEvent<SVGRectElement>, index: number) => {
232	    if (!authoring) return;
233	    e.preventDefault();
234	    e.stopPropagation();
235	    const svg = svgRef.current;
236	    if (!svg) return;
237	    const d = vpDrafts[index];
238	    if (!d || d.viewportLocked) return;
239	    const m = clientToSvgMm(svg, e.clientX, e.clientY);
240	    dragRef.current = { index, grabDX: m.x - d.xMm, grabDY: m.y - d.yMm };
241	
242	    const onMove = (ev: PointerEvent) => {
243	      const dd = dragRef.current;
244	      const el = svgRef.current;
245	      if (!dd || !el) return;
246	      const pt = clientToSvgMm(el, ev.clientX, ev.clientY);
247	      setVpDrafts((prev) => {
248	        const row = prev[dd.index];
249	        if (!row) return prev;
250	        const nx = pt.x - dd.grabDX;
251	        const ny = pt.y - dd.grabDY;
252	        const { xMm, yMm } = clampViewportMmPosition(wMm, hMm, {
253	          xMm: nx,
254	          yMm: ny,
255	          widthMm: row.widthMm,
256	          heightMm: row.heightMm,
257	        });
258	        if (row.xMm === xMm && row.yMm === yMm) return prev;
259	        const next = [...prev];
260	        next[dd.index] = { ...row, xMm, yMm };
261	        return next;
262	      });
263	    };
264	
265	    const onUp = () => {
266	      dragRef.current = null;
267	      window.removeEventListener('pointermove', onMove);
268	      window.removeEventListener('pointerup', onUp);
269	      window.removeEventListener('pointercancel', onUp);
270	    };
271	
272	    window.addEventListener('pointermove', onMove);
273	    window.addEventListener('pointerup', onUp);
274	    window.addEventListener('pointercancel', onUp);
275	  };
276	
277	  const beginResize = (e: ReactPointerEvent<SVGRectElement>, index: number) => {
278	    if (!authoring) return;
279	    e.preventDefault();
280	    e.stopPropagation();
281	    const svg = svgRef.current;
282	    if (!svg) return;
283	    const row = vpDrafts[index];
284	    if (!row || row.viewportLocked) return;
285	    resizeRef.current = { index };
286	
287	    const onMove = (ev: PointerEvent) => {
288	      const rr = resizeRef.current;
289	      const el = svgRef.current;
290	      if (!rr || !el) return;
291	      const pt = clientToSvgMm(el, ev.clientX, ev.clientY);
292	      setVpDrafts((prev) => {
293	        const row = prev[rr.index];
294	        if (!row) return prev;
295	        const nwRaw = pt.x - row.xMm;
296	        const nhRaw = pt.y - row.yMm;
297	        const nextBox = clampViewportMmBox(wMm, hMm, {
298	          xMm: row.xMm,
299	          yMm: row.yMm,
300	          widthMm: nwRaw,
301	          heightMm: nhRaw,
302	        });
303	        if (
304	          row.widthMm === nextBox.widthMm &&
305	          row.heightMm === nextBox.heightMm &&
306	          row.xMm === nextBox.xMm &&
307	          row.yMm === nextBox.yMm
308	        ) {
309	          return prev;
310	        }
311	        const cp = [...prev];
312	        cp[rr.index] = { ...row, ...nextBox };
313	        return cp;
314	      });
315	    };
316	
317	    const onUp = () => {
318	      resizeRef.current = null;
319	      window.removeEventListener('pointermove', onMove);
320	      window.removeEventListener('pointerup', onUp);
321	      window.removeEventListener('pointercancel', onUp);
322	    };
323	
324	    window.addEventListener('pointermove', onMove);
325	    window.addEventListener('pointerup', onUp);
326	    window.addEventListener('pointercancel', onUp);
327	  };
328	
329	  return (
330	    <div
331	      data-testid="sheet-canvas"
332	      className={`overflow-auto rounded border border-border bg-background p-2${scrollCls}`}
333	    >
334	      <div data-testid="sheet-canvas-full-bleed">
335	        <svg
336	          ref={svgRef}
337	          data-testid="sheet-svg"
338	          viewBox={`0 0 ${wMm} ${hMm}`}
339	          className={bleed ? 'h-auto w-full' : 'h-auto max-h-[360px] w-full'}
340	          xmlns="http://www.w3.org/2000/svg"
341	        >
342	          <rect width={wMm} height={hMm} fill="#f8fafc" stroke="#1e293b" strokeWidth={120} />
343	          <rect x={800} y={800} width={wMm - 1600} height={3600} fill="#edf2ff" opacity={0.9} />
344	
345	          <text x={2400} y={2400} className="fill-slate-800" style={{ fontSize: '1200px' }}>
346	            A1 metaphor — {sh.name}
347	          </text>
348	
349	          <text x={2400} y={3600} className="fill-slate-500" style={{ fontSize: '800px' }}>
350	            TB {sh.titleBlock ?? '—'}
351	          </text>
352	
353	          {footerLines
354	            .map((txt) => txt.trim())
355	            .filter(Boolean)
356	            .map((txt, i) => (
357	              <text
358	                key={`tb-${i}-${txt.slice(0, 12)}`}
359	                x={xRight}
360	                y={footerY0 + i * 760}
361	                fill="#334155"
362	                style={{ fontSize: '620px' }}
363	                textAnchor="end"
364	              >
365	                {txt}
366	              </text>
367	            ))}
368	
369	          {revIssSeg ? (
370	            <text
371	              data-testid="sheet-canvas-revision-issue-doc-token"
372	              x={xRight}
373	              y={footerY0 + footerLines.map((txt) => txt.trim()).filter(Boolean).length * 760}
374	              fill="#0369a1"
375	              style={{ fontSize: '520px' }}
376	              textAnchor="end"
377	            >
378	              {revIssSeg}
379	            </text>
380	          ) : null}
381	
382	          {paintRows.map((row) => {
383	            const {
384	              xMm,
385	              yMm,
386	              widthMm,
387	              heightMm,
388	              viewRef,
389	              label,
390	              detailNumber,
391	              scale,
392	              viewportLocked,
393	              viewportRole,
394	              index,
395	            } = row;
396	            const resolved = resolveViewportTitleFromRef(elementsById, viewRef);
397	            const detailReason = detailCalloutUnresolvedReason(elementsById, viewRef);
398	            const isDetailCallout = viewportRole === 'detail_callout';
399	            const primary = isDetailCallout
400	              ? buildPlaceholderDetailTitle(detailNumber, resolved, detailReason)
401	              : (resolved ?? label);
402	            const sub = viewRef.trim() ? viewRef : '';
403	            const parsedRef = parseSheetViewRef(viewRef);
404	            const secId =
405	              modelId && parsedRef?.kind === 'section' && parsedRef.refId ? parsedRef.refId : '';
406	
407	            const secInnerW = Math.max(200, widthMm - 320);
408	            const secInnerH = Math.max(200, heightMm - 2700);
409	
410	            const isScheduleVp = parsedRef?.kind === 'schedule' && Boolean(parsedRef.refId);
411	            const scheduleEl = isScheduleVp ? elementsById[parsedRef!.refId] : undefined;
412	            const scheduleResolved = scheduleEl?.kind === 'schedule';
413	            const scheduleCatRaw =
414	              scheduleResolved && scheduleEl.filters && typeof scheduleEl.filters === 'object'
415	                ? (scheduleEl.filters as Record<string, unknown>).category
416	                : undefined;
417	            const scheduleCat =
418	              typeof scheduleCatRaw === 'string' && scheduleCatRaw.trim()
419	                ? scheduleCatRaw.trim()
420	                : '';
421	            const scheduleCaption = isScheduleVp
422	              ? scheduleResolved
423	                ? `schedule · ${parsedRef!.refId}${scheduleCat ? ` · ${scheduleCat}` : ''}`
424	                : `unresolved schedule · ${parsedRef!.refId}`
425	              : '';
426	
427	            const planLegendHint = planLegendHints[row.key];
428	            const planLegendCaption =
429	              parsedRef?.kind === 'plan' && planLegendHint && planLegendHint.rowCount > 0
430	                ? `legend · ${planLegendHint.rowCount} rows · ${planLegendHint.digestPrefix}…`
431	                : '';
432	
433	            const handle = 560;
434	            const hx = xMm + widthMm - handle;
435	            const hy = yMm + heightMm - handle;
436	            const detailTrim = detailNumber.trim();
437	            const scaleTrim = scale.trim();
438	            const canDragResize = authoring && !viewportLocked;
439	            const vpStroke = isDetailCallout ? '#7c3aed' : '#475569';
440	            const vpDash = isDetailCallout || isScheduleVp ? '480 240' : undefined;
441	
442	            return (
443	              <g key={row.key}>
444	                <rect
445	                  data-testid={`sheet-viewport-${index}`}
446	                  x={xMm}
447	                  y={yMm}
448	                  width={widthMm}
449	                  height={heightMm}
450	                  fill="#ffffff"
451	                  stroke={vpStroke}
452	                  strokeWidth={80}
453	                  strokeDasharray={vpDash}
454	                  className={canDragResize ? 'cursor-move touch-none' : undefined}
455	                  onPointerDown={canDragResize ? (e) => beginDrag(e, index) : undefined}
456	                />
457	                {canDragResize ? (
458	                  <rect
459	                    data-testid={`sheet-viewport-resize-${index}`}
460	                    x={hx}
461	                    y={hy}
462	                    width={handle}
463	                    height={handle}
464	                    fill="#475569"
465	                    stroke="#1e293b"
466	                    strokeWidth={40}
467	                    className="cursor-nwse-resize touch-none"
468	                    onPointerDown={(e) => beginResize(e, index)}
469	                  />
470	                ) : null}
471	                {secId ? (
472	                  <svg
473	                    x={xMm + 160}
474	                    y={yMm + 1500}
475	                    width={secInnerW}
476	                    height={secInnerH}
477	                    viewBox={`0 0 ${secInnerW} ${secInnerH}`}
478	                  >
479	                    <SectionViewportSvg
480	                      modelId={modelId!}
481	                      sectionCutId={secId}
482	                      widthPx={secInnerW}
483	                      heightPx={secInnerH}
484	                    />
485	                  </svg>
486	                ) : null}
487	                {isDetailCallout ? (
488	                  <text x={xMm + 200} y={yMm + 520} fill="#7c3aed" style={{ fontSize: '320px' }}>
489	                    detail callout
490	                  </text>
491	                ) : null}
492	                <text x={xMm + 200} y={yMm + 900} fill="#475569" style={{ fontSize: '600px' }}>
493	                  {primary}
494	                </text>
495	                {detailTrim ? (
496	                  <text
497	                    data-testid={`sheet-viewport-detail-${index}`}
498	                    x={xMm + widthMm - 200}
499	                    y={yMm + 820}
500	                    fill="#475569"
501	                    style={{ fontSize: '480px' }}
502	                    textAnchor="end"
503	                  >
504	                    {detailTrim}
505	                  </text>
506	                ) : null}
507	                {sub ? (
508	                  <text x={xMm + 200} y={yMm + 1400} fill="#64748b" style={{ fontSize: '350px' }}>
509	                    {sub}
510	                  </text>
511	                ) : null}
512	                {scaleTrim ? (
513	                  <text
514	                    data-testid={`sheet-viewport-scale-${index}`}
515	                    x={xMm + 200}
516	                    y={yMm + 1800}
517	                    fill="#64748b"
518	                    style={{ fontSize: '340px' }}
519	                  >
520	                    scale {scaleTrim}
521	                  </text>
522	                ) : null}
523	                {authoring && viewportLocked ? (
524	                  <text
525	                    x={xMm + widthMm - 200}
526	                    y={yMm + heightMm - 320}
527	                    fill="#94a3b8"
528	                    style={{ fontSize: '280px' }}
529	                    textAnchor="end"
530	                  >
531	                    locked
532	                  </text>
533	                ) : null}
534	                {scheduleCaption ? (
535	                  <text
536	                    data-testid={`sheet-viewport-schedule-caption-${index}`}
537	                    x={xMm + 200}
538	                    y={yMm + 2200}
539	                    fill={scheduleResolved ? '#15803d' : '#b45309'}
540	                    style={{ fontSize: '320px' }}
541	                  >
542	                    {scheduleCaption}
543	                  </text>
544	                ) : null}
545	                {planLegendCaption ? (
546	                  <text
547	                    data-testid={`sheet-viewport-plan-legend-caption-${index}`}
548	                    x={xMm + 200}
549	                    y={yMm + 2600}
550	                    fill="#0e7490"
551	                    style={{ fontSize: '300px' }}
552	                  >
553	                    {planLegendCaption}
554	                  </text>
555	                ) : null}
556	              </g>
557	            );
558	          })}
559	        </svg>
560	      </div>
561	
562	      <SheetDocumentationManifest
563	        sheet={sh}
564	        modelId={modelId}
565	        elementsById={elementsById}
566	        authoring={authoring}
567	        tbDraft={tbDraft}
568	        vpDrafts={vpDrafts}
569	      />
570	
571	      {props.onUpsertSemantic ? (
572	        <>
573	          <SheetTitleblockEditor
574	            sheetId={sh.id}
575	            sheetName={sh.name}
576	            draft={tbDraft}
577	            priorTitleblockParameters={tp as Record<string, string>}
578	            setDraft={setTbDraft}
579	            onUpsertSemantic={props.onUpsertSemantic}
580	          />
581	
582	          <SheetViewportEditor
583	            sheetId={sh.id}
584	            sheetName={sh.name}
585	            drafts={vpDrafts}
586	            setDrafts={setVpDrafts}
587	            elementsById={elementsById}
588	            onUpsertSemantic={props.onUpsertSemantic}
589	          />
590	        </>
591	      ) : null}
592	
593	      <div className="mt-1 font-mono text-[10px] text-muted">{sh.id}</div>
594	    </div>
595	  );
596	}
