598	/** Paper-space preview: titleblock stripe + viewport frames from semantic `sheet` elements. */
599	
600	export function SheetCanvas(props: {
601	  elementsById: Record<string, Element>;
602	  preferredSheetId?: string;
603	  modelId?: string;
604	  /**
605	   * When true, drop scroll/max-height clamps so PNG evidence can rasterize the entire sheet SVG
606	   * (drive via `/?evidenceSheetFull=1` in Playwright).
607	   */
608	  evidenceFullBleed?: boolean;
609	  /** When set, show a replayable `upsertSheetViewports` authoring band (WP-E05/E06/E04). */
610	  onUpsertSemantic?: (cmd: Record<string, unknown>) => void;
611	}) {
612	  const sheets = Object.values(props.elementsById).filter(
