# Module-level in-memory store for v3 sheet-anchored comments and notification
# chips. Keyed by model_id; no DB migration required for this WP.
_v3_comments_store: dict[str, list[dict]] = {}
_v3_chip_store: dict[str, list[dict]] = {}  # key: model_id; each entry: SheetCommentChipEntry payload


def _get_v3_comments(model_id: str) -> list[dict]:
