class V3CommentCreateBody(BaseModel):
    model_config = ConfigDict(populate_by_name=True, extra="ignore")
    thread_id: str | None = Field(default=None, alias="threadId")
    author_id: str = Field(alias="authorId")
    body: str
    anchor: dict


@api_router.post("/v3/models/{model_id}/comments")
async def v3_create_comment(
    model_id: UUID,
    body: V3CommentCreateBody,
    session: AsyncSession = Depends(get_session),
) -> dict[str, Any]:
    import time as _time

    from bim_ai.comments import Comment, SheetAnchor, resolve_sheet_anchor_binding

    cid = str(uuid4())
    tid = body.thread_id if body.thread_id else cid
    anchor_raw = dict(body.anchor)

    # If this is a sheet anchor, resolve source binding from the pixel map (if available).
    if anchor_raw.get("kind") == "sheet":
        sheet_anchor = SheetAnchor.model_validate(anchor_raw)
        # Fetch pixel map for the sheet and resolve binding.
        sheet_id = sheet_anchor.sheet_id
        pixel_map = await _fetch_sheet_pixel_map(session, str(model_id), sheet_id)
        sheet_anchor = resolve_sheet_anchor_binding(sheet_anchor, pixel_map)
        anchor_raw = sheet_anchor.model_dump(by_alias=True)

    raw: dict[str, Any] = {
        "id": cid,
        "modelId": str(model_id),
        "threadId": tid,
        "authorId": body.author_id,
        "body": body.body,
        "anchor": anchor_raw,
        "createdAt": int(_time.time() * 1000),
        "isOrphaned": False,
    }
    comment = Comment.model_validate(raw)
    _get_v3_comments(str(model_id)).append(comment.model_dump(by_alias=True))

    # Emit sheet_comment_chip notification when source view is known.
    if comment.anchor.kind == "sheet" and comment.anchor.source_view_id is not None:
        chip_payload: dict[str, Any] = {
            "kind": "sheet_comment_chip",
            "viewId": comment.anchor.source_view_id,
            "sheetId": comment.anchor.sheet_id,
            "commentId": cid,
            "sheetNumber": _resolve_sheet_number(session, str(model_id), comment.anchor.sheet_id),
        }
        _get_v3_chips(str(model_id)).append(chip_payload)

    return comment.model_dump(by_alias=True)


def _resolve_sheet_number(session: Any, model_id: str, sheet_id: str) -> str:
    """Best-effort: return the sheet number from the stored document."""
    return sheet_id  # v3 approximation — caller can enrich if needed


async def _fetch_sheet_pixel_map(
    session: AsyncSession,
    model_id: str,
    sheet_id: str,
) -> dict[tuple[int, int], tuple[str, str]]:
    """Build approximate pixel map from the sheet's viewportsMm / viewPlacements."""
    try:
        row = await load_model_row(session, UUID(model_id))
    except Exception:
        return {}
    if row is None:
        return {}
    try:
        from bim_ai.document import Document as _Document

        doc = _Document.model_validate(row.document)
    except Exception:
        return {}
    sheet_elem = doc.elements.get(sheet_id)
    if sheet_elem is None or getattr(sheet_elem, "kind", None) != "sheet":
        return {}

    pixel_map: dict[tuple[int, int], tuple[str, str]] = {}
    # Walk viewPlacements (new format) then viewportsMm (legacy format).
    vps = getattr(sheet_elem, "view_placements", None) or getattr(sheet_elem, "viewPlacements", None) or []
    for vp in vps:
        if isinstance(vp, dict):
            vid = vp.get("viewId", "")
            min_xy = vp.get("minXY", {})
            size = vp.get("size", {})
            cx = int(min_xy.get("x", 0) + size.get("x", 0) / 2)
            cy = int(min_xy.get("y", 0) + size.get("y", 0) / 2)
        else:
            vid = getattr(vp, "view_id", "") or getattr(vp, "viewId", "")
            min_xy = getattr(vp, "min_x_y", None) or getattr(vp, "minXY", None) or {}
            size = getattr(vp, "size", None) or {}
            if isinstance(min_xy, dict):
                cx = int(min_xy.get("x", 0) + (size.get("x", 0) if isinstance(size, dict) else 0) / 2)
                cy = int(min_xy.get("y", 0) + (size.get("y", 0) if isinstance(size, dict) else 0) / 2)
            else:
                cx = int(getattr(min_xy, "x", 0))
                cy = int(getattr(min_xy, "y", 0))
        if vid:
            pixel_map[(cx, cy)] = (vid, "")
    # Also walk legacy viewportsMm list.
    viewports_mm = getattr(sheet_elem, "viewports_mm", None) or getattr(sheet_elem, "viewportsMm", None) or []
    for vp in viewports_mm:
        if not isinstance(vp, dict):
            continue
        vid = str(vp.get("viewRef", vp.get("view_ref", vp.get("viewportId", ""))))
        x = float(vp.get("xMm", vp.get("x_mm", 0)))
        y = float(vp.get("yMm", vp.get("y_mm", 0)))
        w = float(vp.get("widthMm", vp.get("width_mm", 0)))
        h = float(vp.get("heightMm", vp.get("height_mm", 0)))
        cx = int(x + w / 2)
        cy = int(y + h / 2)
        if vid:
            pixel_map[(cx, cy)] = (vid, "")
    return pixel_map


@api_router.post("/v3/models/{model_id}/comments/{comment_id}/resolve")
async def v3_resolve_comment(
    model_id: UUID,
    comment_id: str,
) -> dict[str, Any]:
    import time as _time

    comments = _get_v3_comments(str(model_id))
    target: dict | None = None
    for i, c in enumerate(comments):
        if c.get("id") == comment_id:
            target = dict(c)
            target["resolvedAt"] = int(_time.time() * 1000)
            comments[i] = target
            break
    if target is None:
        raise HTTPException(status_code=404, detail="Comment not found")

    # Bidirectional resolve: if target is a sheet anchor, also resolve any
    # comment in the same thread whose element anchor matches the sourceElementId.
    # Symmetric: if target is an element anchor, also resolve matching sheet-side thread.
    _bidirectional_resolve(comments, target, _time.time())
    return target


def _bidirectional_resolve(
    comments: list[dict],
    resolved_comment: dict,
    resolve_ts: float,
) -> None:
    """Resolve counterpart comments in the same thread across anchor types."""
    resolved_at = int(resolve_ts * 1000)
    thread_id = resolved_comment.get("threadId")
    anchor = resolved_comment.get("anchor", {})

    if anchor.get("kind") == "sheet":
        source_elem_id = anchor.get("sourceElementId")
        if not source_elem_id:
            return
        for i, c in enumerate(comments):
            if c.get("threadId") != thread_id:
                continue
            ca = c.get("anchor", {})
            if ca.get("kind") == "element" and ca.get("elementId") == source_elem_id:
                if c.get("resolvedAt") is None:
                    updated = dict(c)
                    updated["resolvedAt"] = resolved_at
                    comments[i] = updated

    elif anchor.get("kind") == "element":
        elem_id = anchor.get("elementId")
        if not elem_id:
            return
        for i, c in enumerate(comments):
            if c.get("threadId") != thread_id:
                continue
            ca = c.get("anchor", {})
            if ca.get("kind") == "sheet" and ca.get("sourceElementId") == elem_id:
                if c.get("resolvedAt") is None:
                    updated = dict(c)
                    updated["resolvedAt"] = resolved_at
                    comments[i] = updated


@api_router.get("/v3/models/{model_id}/sheets/{sheet_id}/pixel-map")
async def v3_sheet_pixel_map(
    model_id: UUID,
    sheet_id: str,
    authorization: Annotated[str | None, Query(alias="authorization")] = None,
    session: AsyncSession = Depends(get_session),
) -> dict[str, Any]:
    """Return a sparse pixel-map for source-element binding on the sheet canvas."""
    row = await load_model_row(session, model_id)
    if row is None:
        raise HTTPException(status_code=404, detail="Model not found")
    raw_map = await _fetch_sheet_pixel_map(session, str(model_id), sheet_id)
    wire: dict[str, dict[str, str]] = {}
    for (x, y), (view_id, element_id) in raw_map.items():
        key = f"{x},{y}"
        entry: dict[str, str] = {"sourceViewId": view_id}
        if element_id:
            entry["sourceElementId"] = element_id
        wire[key] = entry
    return {"map": wire}


