    createdAt: String(c.createdAt),
  }));

  const activeComment = activePinId ? uxComments.filter((c) => c.id === activePinId) : [];

  return (
    <div
      data-testid="sheet-review-surface"
      className="relative flex h-full w-full flex-col"
      style={{ background: 'var(--color-surface-1)' }}
    >
      <div
        className="relative flex-1 overflow-hidden"
        style={{ paddingBottom: 40 }}
        onClick={handleCanvasClick}
        ref={svgRef as unknown as React.RefObject<HTMLDivElement>}
      >
        <SheetCanvas
          elementsById={elementsById}
          preferredSheetId={sheetId}
          modelId={modelId}
          evidenceFullBleed
        />
        {sheetComments.map((c) => {
          const anchor = c.anchor as SheetAnchor;
          return (
            <CommentPinOverlay
              key={c.id}
              xPx={anchor.xPx}
              yPx={anchor.yPx}
              resolved={c.resolvedAt != null}
              active={activePinId === c.id}
              onClick={() => setActivePinId(activePinId === c.id ? null : c.id)}
            />
          );
        })}
        {pendingPin && (
          <div
            style={{
              position: 'absolute',
              left: pendingPin.xPx - 8,
              top: pendingPin.yPx - 8,
              width: 16,
              height: 16,
              borderRadius: '50%',
              background: 'var(--draft-comment-pin)',
              border: '2px solid var(--color-surface-1)',
              pointerEvents: 'none',
            }}
          />
        )}
      </div>

      {(activePinId || pendingPin) && (
        <div
          className="absolute"
          style={{
            left: (activePinId
              ? ((sheetComments.find((c) => c.id === activePinId)?.anchor as SheetAnchor | undefined)
                  ?.xPx ?? 0)
              : (pendingPin?.xPx ?? 0)) + 8,
            top: (activePinId
              ? ((sheetComments.find((c) => c.id === activePinId)?.anchor as SheetAnchor | undefined)
                  ?.yPx ?? 0)
              : (pendingPin?.yPx ?? 0)) + 8,
            zIndex: 10,
          }}
          style2={{ '--space-2': '8px' } as React.CSSProperties}
        >
          <CommentsPanel
            comments={activePinId ? activeComment : []}
            userDisplay="You"
            onPost={handlePost}
            onResolve={handleResolve}
            onClose={() => {
              setActivePinId(null);
              setPendingPin(null);
            }}
          />
        </div>
      )}

      <ReviewToolbar mode={mode} onModeChange={setMode} readOnly={readOnly} />
    </div>
  );
}

function CommentPinOverlay({
  xPx,
  yPx,
  resolved,
  active,
  onClick,
}: {
  xPx: number;
  yPx: number;
  resolved: boolean;
  active: boolean;
  onClick: () => void;
}): JSX.Element {
  return (
    <button
      type="button"
      aria-label="Sheet comment"
      onClick={(e) => {
        e.stopPropagation();
        onClick();
      }}
      style={{
        position: 'absolute',
        left: xPx - 8,
        top: yPx - 8,
        width: 16,
        height: 16,
        borderRadius: '50%',
        background: resolved ? 'var(--color-muted)' : 'var(--draft-comment-pin)',
        border: active
          ? '2px solid var(--color-accent)'
          : '2px solid var(--color-surface-1)',
        cursor: 'pointer',
        opacity: resolved ? 0.4 : 1,
        padding: 0,
      }}
    />
  );
}

function ReviewToolbar({
  mode,
  onModeChange,
  readOnly,
}: {
  mode: ReviewMode;
  onModeChange: (m: ReviewMode) => void;
  readOnly: boolean;
}): JSX.Element {
  return (
    <div
      data-testid="sheet-review-toolbar"
      className="flex items-center gap-2 border-t border-border px-4"
      style={{
        height: 40,
        background: 'var(--color-surface-strong)',
        borderRadius: 0,
      }}
    >
      {REVIEW_TOOLS.map(({ mode: m, label, title }) => (
        <button
          key={m}
          type="button"
          data-testid={`review-tool-${m}`}
          disabled={readOnly && m !== 'mr'}
          aria-pressed={mode === m}
          title={title}
          onClick={() => onModeChange(m)}
          className={[
            'rounded px-3 py-1 text-xs font-semibold transition-colors',
            mode === m
              ? 'bg-accent text-accent-foreground'
              : 'text-muted hover:bg-surface hover:text-foreground',
            readOnly && m !== 'mr' ? 'cursor-not-allowed opacity-40' : '',
          ]
            .join(' ')
            .trim()}
        >
          {label}
        </button>
      ))}
    </div>
  );
}

